### Example 2: Keyboard Input with a GUI

This program uses the `tkinter` library to create a simple GUI and the `pynput` library to listen for keyboard input.

```python
import tkinter as tk
from pynput import keyboard

class KeyboardInputGUI:
    def __init__(self):
        self.root = tk.Tk()
        self.root.title('Keyboard Input GUI')
        self.label = tk.Label(self.root, text='Press a key:')
        self.label.pack()
        self.entry = tk.Entry(self.root)
        self.entry.pack()
        self.listener = keyboard.Listener(on_press=self.on_press, on_release=self.on_release)
        self.listener.start()

    def on_press(self, key):
        try:
            self.entry.insert(tk.END, key.char)
        except AttributeError:
            self.entry.insert(tk.END, str(key))

    def on_release(self, key):
        if key == keyboard.Key.esc:
            # Stop listener
            self.listener.stop()
            self.root.destroy()

    def run(self):
        self.root.mainloop()

if __name__ == '__main__':
    gui = KeyboardInputGUI()
    gui.run()
```

